import "./App.css";
import React, { useState, useEffect } from "react";

function App() {
  const [search, setSearch] = useState("");
  const [sortType, setSortType] = useState("");
  const [page, setPage] = useState("list"); // list or add
  const [tasks, setTasks] = useState([]);
  const [task, setTask] = useState("");
  const [priority, setPriority] = useState("Medium");
  const [dueDate, setDueDate] = useState("");

  // Add Task
  const addTask = async () => {
    try {
      await fetch("http://localhost:5000/addTask", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ task, priority, dueDate }),
      });

      alert("Task Added Successfully");

      setTask("");
      setPriority("Medium");
      setDueDate("");

      fetchTasks();
      setPage("list"); // go back to list page
    } catch (error) {
      console.log(error);
    }
  };

  // Fetch Tasks
  const fetchTasks = async () => {
    const res = await fetch("http://localhost:5000/tasks");
    const data = await res.json();
    setTasks(data);
  };

  // Delete Task
  const deleteTask = async (id) => {
    await fetch(`http://localhost:5000/deleteTask/${id}`, {
      method: "DELETE",
    });
    fetchTasks();
  };

  // Update Task
  const updateTask = async (id) => {
    await fetch(`http://localhost:5000/updateTask/${id}`, {
      method: "PUT",
    });
    fetchTasks();
  };
  // Toggle Important
  const toggleImportant = async (id) => {
    try {
      await fetch(`http://localhost:5000/toggleImportant/${id}`, {
        method: "PUT",
      });

      fetchTasks(); // refresh
    } catch (error) {
      console.log(error);
    }
  };
  useEffect(() => {
    fetchTasks();
  }, []);

  return (
    <div style={{ padding: "20px" }}>
      <h1>Task Manager</h1>

      {/* ---------- LIST PAGE ---------- */}
      {page === "list" && (
        <>
          <button onClick={() => setPage("add")}>➕ Add Task</button>

          <h2>Task List</h2>
          {/* Search */}
          <label>
            <b>Search tasks</b>
          </label>
          <br />
          <input
            type="text"
            placeholder="Search"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />

          <br />
          <br />

          {/* Sort */}
          <label>
            <b>Sort tasks</b>
          </label>
          <br />
          <select onChange={(e) => setSortType(e.target.value)}>
            <option value="">Sort By</option>
            <option value="priority">Priority</option>
            <option value="dueDate">Due Date</option>
            <option value="status">Status</option>
          </select>

          <br />
          <br />
          <ul>
            {tasks
              .filter((t) =>
                t.task.toLowerCase().includes(search.toLowerCase()),
              )
              .sort((a, b) => {
                if (sortType === "priority") {
                  const order = { High: 1, Medium: 2, Low: 3 };
                  return order[a.priority] - order[b.priority];
                }
                if (sortType === "dueDate") {
                  return new Date(a.dueDate) - new Date(b.dueDate);
                }
                if (sortType === "status") {
                  const order = { Pending: 1, Completed: 2 };
                  return order[a.status] - order[b.status];
                }
                return 0;
              })
              .map((t) => (
                <li key={t._id}>
                  {/* ⭐ STAR BUTTON */}
                  <span
                    style={{
                      cursor: "pointer",
                      fontSize: "20px",
                      marginRight: "8px",
                    }}
                    onClick={() => toggleImportant(t._id)}
                  >
                    {t.important ? "⭐" : "☆"}
                  </span>
                  {t.task} - {t.priority} - {t.status}
                  {t.status === "Pending" && (
                    <button onClick={() => updateTask(t._id)}>Complete</button>
                  )}
                  <button onClick={() => deleteTask(t._id)}>Delete</button>
                </li>
              ))}
          </ul>
        </>
      )}

      {/* ---------- ADD PAGE ---------- */}
      {page === "add" && (
        <>
          <button onClick={() => setPage("list")}>⬅ Back</button>

          <h2>Add Task</h2>

          <label>
            <b>Enter Task</b>
          </label>
          <br />
          <input
            type="text"
            value={task}
            onChange={(e) => setTask(e.target.value)}
          />

          <br />
          <br />

          <label>
            <b>Priority of the Task</b>
          </label>
          <br />
          <select
            value={priority}
            onChange={(e) => setPriority(e.target.value)}
          >
            <option>High</option>
            <option>Medium</option>
            <option>Low</option>
          </select>

          <br />
          <br />

          <label>
            <b>Due Date</b>
          </label>
          <br />
          <input
            type="date"
            value={dueDate}
            onChange={(e) => setDueDate(e.target.value)}
          />

          <br />
          <br />

          <button onClick={addTask}>Add Task</button>
        </>
      )}
    </div>
  );
}

export default App;
